+        .await;
+
+    let (connector, _signing_key) = setup_connector(&server, "sq-ready").await;
+    let doctor = serde_json::to_value(connector.doctor()).unwrap();
+    assert_doctor_response_valid(&doctor);
+    assert_eq!(doctor["ready"], true);
